class Solution {
    public int makeTheIntegerZero(int num1, int num2) {
        if (num2 == 0) return num1 == 0 ? 0 : -1;
        int gcd = gcd(Math.abs(num1), Math.abs(num2));
        if (num1 % gcd != 0) return -1;
        int res = 0;
        while (num1 != 0) {
            int i = (int) Math.floor(Math.log(Math.abs(num1)) / Math.log(2));
            if (i > 60) i = 60;
            num1 -= (2 * i + num2);
            res++;
        }
        return res;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
